exercises.solution:
class Animal:
    def __init__(self, name):
        self.name = name

class Dog(Animal):
    def __init__(self, name, breed):
        super().__init__(name)
        self.breed = breed
    def info(self):
        return f"{self.name}: {self.breed}"

def make(name, breed):
    return Dog(name, breed).info()
